const VALID_THEME_TYPES: ReadonlySet<string> = new Set<ThemeType>([
  "mountain_escapes", "lake_escapes", "coastal_landscapes", "island_getaways",
  "forest_walks", "national_park_weekends", "protected_landscapes", "river_valleys",
  "waterfall_destinations", "nature_photography_spots", "sunrise_viewpoints",
  "hiking_areas", "cycling_friendly_areas", "wildlife_areas", "unesco_nature_areas",
  "cross_border_nature_areas", "family_outdoor_escapes", "scenic_drives",
  "weekend_nature_retreats", "alpine_landscapes", "nordic_nature", "mediterranean_nature",
  "atlantic_coast_nature", "great_lakes_nature", "volcanic_landscapes", "wetlands_marshes",
  "rural_countryside_escapes",
]);
const MIN_PLACES=5, MAX_PLACES=50, MIN_CITIES=2, MAX_CITIES=50, MIN_RELATED=2, MAX_RELATED=15;
// thematic collections are nature-only (no towns/cities/cultural sites as places)
const NATURE_CATEGORIES: ReadonlySet<string> = new Set(["nature","park","mountain","lake","beach","island","waterfront","family_outdoor","general_weekend_place"]);
const NORDIC_COUNTRIES: ReadonlySet<string> = new Set(["sweden","finland","denmark","norway","iceland"]);
const EUROPE_COUNTRIES: ReadonlySet<string> = new Set(["austria","belgium","bulgaria","croatia","czechia","denmark","estonia","finland","france","germany","greece","hungary","ireland","italy","latvia","lithuania","luxembourg","netherlands","poland","portugal","romania","slovakia","slovenia","spain","sweden","united-kingdom"]);

function assertThematicCollections(cols: readonly ThematicCollection[]): void {
  const citySlugs = new Set(cities.map((c) => c.slug));
  const placeSlugs = new Set(nearbyWeekendPlaces.map((p) => p.slug));
  const placeCategory = new Map(nearbyWeekendPlaces.map((p) => [p.slug, p.category]));
  const placeCountry = new Map(nearbyWeekendPlaces.map((p) => [p.slug, p.countrySlug]));
  const allSlugs = new Set(cols.map((c) => c.slug));
  const slugSeen = new Set<string>();
  const memberSets = new Map<string, string>();
  const errors: string[] = [];
  for (const c of cols) {
    if (slugSeen.has(c.slug)) errors.push(`${c.slug}: duplicate slug`);
    slugSeen.add(c.slug);
    if (!VALID_THEME_TYPES.has(c.themeType)) errors.push(`${c.slug}: invalid themeType ${c.themeType}`);
    if (c.nearbyPlaces.length < MIN_PLACES || c.nearbyPlaces.length > MAX_PLACES) errors.push(`${c.slug}: ${c.nearbyPlaces.length} places out of 5-50`);
    if (c.cities.length < MIN_CITIES || c.cities.length > MAX_CITIES) errors.push(`${c.slug}: ${c.cities.length} cities out of 2-50`);
    const pSeen = new Set<string>();
    for (const p of c.nearbyPlaces) {
      if (pSeen.has(p)) errors.push(`${c.slug}: duplicate place ${p}`);
      pSeen.add(p);
      if (!placeSlugs.has(p)) errors.push(`${c.slug}: place ${p} not found`);
      const cat = placeCategory.get(p);
      if (cat && !NATURE_CATEGORIES.has(cat)) errors.push(`${c.slug}: non-nature place ${p} (${cat})`);
      const pc = placeCountry.get(p);
      if (c.themeType === "nordic_nature" && pc && !NORDIC_COUNTRIES.has(pc)) errors.push(`${c.slug}: non-Nordic place ${p} (${pc})`);
      if (c.themeType === "alpine_landscapes" && pc && !EUROPE_COUNTRIES.has(pc)) errors.push(`${c.slug}: non-European alpine place ${p} (${pc})`);
    }
    const cSeen = new Set<string>();
    for (const ct of c.cities) {
      if (cSeen.has(ct)) errors.push(`${c.slug}: duplicate city ${ct}`);
      cSeen.add(ct);
      if (!citySlugs.has(ct)) errors.push(`${c.slug}: city ${ct} not found`);
    }
    for (const p of c.featuredPlaces) if (!pSeen.has(p)) errors.push(`${c.slug}: featuredPlace ${p} not in nearbyPlaces`);
    for (const ct of c.featuredCities) if (!cSeen.has(ct)) errors.push(`${c.slug}: featuredCity ${ct} not in cities`);
    for (const ct of c.weekendTrips) if (!cSeen.has(ct)) errors.push(`${c.slug}: weekendTrips ${ct} not in cities`);
    for (const ct of c.visualGuides) if (!cSeen.has(ct)) errors.push(`${c.slug}: visualGuides ${ct} not in cities`);
    if (c.relatedCollections.length < MIN_RELATED || c.relatedCollections.length > MAX_RELATED) errors.push(`${c.slug}: ${c.relatedCollections.length} related out of 2-15`);
    const rSeen = new Set<string>();
    for (const r of c.relatedCollections) {
      if (r === c.slug) errors.push(`${c.slug}: related self-reference`);
      if (rSeen.has(r)) errors.push(`${c.slug}: duplicate related ${r}`);
      rSeen.add(r);
      if (!allSlugs.has(r)) errors.push(`${c.slug}: related ${r} not found`);
    }
    if (c.officialPhotoCount < 0 || c.communityPhotoCount < 0 || c.photoEligiblePlaceCount < 0) errors.push(`${c.slug}: negative photo counter`);
    if (c.photoEligiblePlaceCount > c.nearbyPlaces.length) errors.push(`${c.slug}: photoEligiblePlaceCount exceeds place count`);
    const key = [...c.nearbyPlaces].sort().join(",");
    if (memberSets.has(key)) errors.push(`${c.slug}: duplicate membership set of ${memberSets.get(key)}`);
    else memberSets.set(key, c.slug);
  }
  if (errors.length > 0) {
    throw new Error(`Invalid thematic collections (${errors.length}):\n  - ${errors.slice(0,40).join("\n  - ")}`);
  }
}

assertThematicCollections(THEMATIC_COLLECTIONS);

const BY_CITY = new Map<string, ThematicCollection[]>();
const BY_PLACE = new Map<string, ThematicCollection[]>();
const BY_SLUG = new Map<string, ThematicCollection>();
for (const c of THEMATIC_COLLECTIONS) {
  BY_SLUG.set(c.slug, c);
  for (const ct of c.cities) { const a = BY_CITY.get(ct) ?? []; a.push(c); BY_CITY.set(ct, a); }
  for (const p of c.nearbyPlaces) { const a = BY_PLACE.get(p) ?? []; a.push(c); BY_PLACE.set(p, a); }
}

export function getAllThematicCollections(): readonly ThematicCollection[] { return THEMATIC_COLLECTIONS; }
export function getThematicCollectionBySlug(slug: string): ThematicCollection | undefined { return BY_SLUG.get(slug); }
export function getThematicCollectionsForCity(citySlug: string): readonly ThematicCollection[] { return BY_CITY.get(citySlug) ?? []; }
export function getThematicCollectionsForPlace(placeSlug: string): readonly ThematicCollection[] { return BY_PLACE.get(placeSlug) ?? []; }
export function getRelatedThematicCollections(slug: string): ThematicCollection[] {
  const c = BY_SLUG.get(slug);
  if (!c) return [];
  return c.relatedCollections.map((s) => BY_SLUG.get(s)).filter((x): x is ThematicCollection => Boolean(x));
}

